import csv
import random
import math

def read_data(csv_path):
    examples = []
    with open(csv_path, 'r') as csv_file:
        csv_reader = csv.DictReader(csv_file)
        for example in csv_reader:
            for k, v in example.items():
                if v == '':
                    example[k] = None
                else:
                    try:
                        example[k] = float(v)
                    except ValueError:
                        example[k] = v
            examples.append(example)
    if len(examples) > 0:
        keys = list(examples[0].keys())
        if len(keys) <= 2:
            examples = []
            with open(csv_path, 'r') as csv_file:
                csv_reader = csv.DictReader(csv_file, delimiter=';')
                for example in csv_reader:
                    for k, v in example.items():
                        if v == '':
                            example[k] = None
                        else:
                            v2 = v.replace(',', '.')
                            try:
                                example[k] = float(v2)
                            except ValueError:
                                example[k] = v
                    examples.append(example)
    return examples

def train_test_split(examples, test_perc):
    test_size = round(test_perc * len(examples))
    shuffled = random.sample(examples, len(examples))
    return shuffled[test_size:], shuffled[:test_size]

class LeafNode:
    __slots__ = ('pred_class', 'pred_class_count', 'total_count', 'prob')

    def __init__(self, pred_class, pred_class_count, total_count):
        self.pred_class = pred_class
        self.pred_class_count = pred_class_count
        self.total_count = total_count
        self.prob = pred_class_count / total_count

    def classify(self, example):
        return self.pred_class, self.prob

class DecisionNode:
    __slots__ = ('test_attr_name', 'test_attr_threshold', 'child_lt', 'child_ge', 'child_miss')

    def __init__(self, test_attr_name, test_attr_threshold, child_lt, child_ge, child_miss):
        self.test_attr_name = test_attr_name
        self.test_attr_threshold = test_attr_threshold
        self.child_ge = child_ge
        self.child_lt = child_lt
        self.child_miss = child_miss

    def classify(self, example):
        test_val = example[self.test_attr_name]
        if test_val is None:
            return self.child_miss.classify(example)
        elif test_val < self.test_attr_threshold:
            return self.child_lt.classify(example)
        else:
            return self.child_ge.classify(example)

def entropy(examples, class_label):
    counts = {}
    for ex in examples:
        c = ex[class_label]
        counts[c] = counts.get(c, 0) + 1
    n = len(examples)
    s = 0.0
    log2 = math.log2
    for count in counts.values():
        p = count / n
        if p > 0:
            s -= p * log2(p)
    return s

def get_predictive_class(examples, class_label):
    counts = {}
    for ex in examples:
        c = ex[class_label]
        counts[c] = counts.get(c, 0) + 1
    best_class = max(counts, key=counts.get)
    return best_class, counts[best_class]

def get_best_attribute_and_split(attribute_set, examples, class_label):
    parent_entropy = entropy(examples, class_label)
    n = len(examples)
    best_gain = 0.0
    best_attr = None
    best_threshold = None

    for attr in attribute_set:
        values = sorted(
            set(ex[attr] for ex in examples if ex[attr] is not None and isinstance(ex[attr], float))  # ← only numeric
        )
        if len(values) < 2:  # ← skip if not enough numeric values to split
            continue
        for i in range(len(values) - 1):
            threshold = (values[i] + values[i + 1]) / 2.0
            lt = [ex for ex in examples if ex[attr] is not None and isinstance(ex[attr], float) and ex[attr] < threshold]
            ge = [ex for ex in examples if ex[attr] is not None and isinstance(ex[attr], float) and ex[attr] >= threshold]
            miss = [ex for ex in examples if ex[attr] is None or not isinstance(ex[attr], float)]
            if not lt or not ge:
                continue
            weighted_entropy = (len(lt) / n) * entropy(lt, class_label) + \
                               (len(ge) / n) * entropy(ge, class_label)
            if miss:
                weighted_entropy += (len(miss) / n) * entropy(miss, class_label)
            gain = parent_entropy - weighted_entropy
            if gain > best_gain:
                best_gain = gain
                best_attr = attr
                best_threshold = threshold

    return best_attr, best_threshold, best_gain
    
def build_tree(examples, class_label, attribute_set, max_depth=None, depth=0):
    pred_class, pred_count = get_predictive_class(examples, class_label)
    total = len(examples)

    if len(set(ex[class_label] for ex in examples)) == 1:
        return LeafNode(pred_class, pred_count, total)

    if not attribute_set or (max_depth is not None and depth >= max_depth):
        return LeafNode(pred_class, pred_count, total)

    best_attr, best_threshold, best_gain = get_best_attribute_and_split(
        attribute_set, examples, class_label
    )

    if best_attr is None or best_gain <= 0:
        return LeafNode(pred_class, pred_count, total)

    lt = [ex for ex in examples if ex[best_attr] is not None and ex[best_attr] < best_threshold]
    ge = [ex for ex in examples if ex[best_attr] is not None and ex[best_attr] >= best_threshold]
    miss = [ex for ex in examples if ex[best_attr] is None]

    child_lt = build_tree(lt, class_label, attribute_set, max_depth, depth + 1) \
        if lt else LeafNode(pred_class, pred_count, total)
    child_ge = build_tree(ge, class_label, attribute_set, max_depth, depth + 1) \
        if ge else LeafNode(pred_class, pred_count, total)
    child_miss = build_tree(miss, class_label, attribute_set, max_depth, depth + 1) \
        if miss else LeafNode(pred_class, pred_count, total)

    return DecisionNode(best_attr, best_threshold, child_lt, child_ge, child_miss)

def evaluate(tree, examples, class_label):
    correct = sum(
        1 for ex in examples if tree.classify(ex)[0] == ex[class_label]
    )
    return correct / len(examples) if examples else 0.0

if __name__ == '__main__':
    import sys
    csv_path = sys.argv[1] if len(sys.argv) > 1 else 'town_vax_data.csv'
    examples = read_data(csv_path)
    keys = list(examples[0].keys())
    class_label = keys[-1]
    attribute_set = [k for k in keys if k != class_label]
    train, test = train_test_split(examples, test_perc=0.2)
    tree = build_tree(train, class_label, attribute_set)
    accuracy = evaluate(tree, test, class_label)
    print(f"ACCURACY={accuracy:.6f}")